    static FILE* __glide_lsp_log_fp = NULL;
    void __glide_lsp_log_open(const char* path) {
        if (path == NULL || !*path) return;
        __glide_lsp_log_fp = fopen(path, "w");
        if (!__glide_lsp_log_fp) return;
        setvbuf(__glide_lsp_log_fp, NULL, _IONBF, 0);   /* unbuffered: crash-time data survives */
        /* Redirect stderr into the log so SIGSEGV handlers (and any
           rogue fprintf(stderr, ...)) end up in the same place. */
        int fd = fileno(__glide_lsp_log_fp);
        if (fd >= 0) {
            fflush(stderr);
            dup2(fd, fileno(stderr));
        }
    }
    void __glide_lsp_log(const char* msg) {
        if (__glide_lsp_log_fp == NULL || msg == NULL) return;
        time_t t = time(NULL);
        struct tm* lt = localtime(&t);
        if (lt) {
            fprintf(__glide_lsp_log_fp, "[%02d:%02d:%02d] %s\n",
                lt->tm_hour, lt->tm_min, lt->tm_sec, msg);
        } else {
            fprintf(__glide_lsp_log_fp, "%s\n", msg);
        }
    }


