    // Inflate a gzip-wrapped stream. Doubles the output buffer on
    // demand — typical compression ratios mean ~3x is plenty, but
    // we resize unconditionally if zlib reports Z_BUF_ERROR. Returns
    // a fresh malloc'd buffer; NULL on any error. `*out_len` ends up
    // at the decompressed byte count.
    void* __glide_gunzip_decode(const char* input, int in_len, int* out_len) {
        if (in_len <= 0) { *out_len = 0; return NULL; }
        size_t cap = (size_t)in_len * 4 + 64;
        unsigned char* buf = (unsigned char*)malloc(cap);
        if (!buf) { *out_len = 0; return NULL; }

        z_stream zs;
        memset(&zs, 0, sizeof(zs));
        // 15 + 32 = auto-detect gzip OR zlib wrapper.
        if (inflateInit2(&zs, 15 + 32) != Z_OK) {
            free(buf); *out_len = 0; return NULL;
        }
        zs.next_in  = (Bytef*)input;
        zs.avail_in = (uInt)in_len;
        zs.next_out = buf;
        zs.avail_out = (uInt)cap;

        for (;;) {
            int rc = inflate(&zs, Z_NO_FLUSH);
            if (rc == Z_STREAM_END) break;
            if (rc == Z_OK && zs.avail_out > 0) continue;
            if (rc != Z_OK && rc != Z_BUF_ERROR) {
                inflateEnd(&zs); free(buf); *out_len = 0; return NULL;
            }
            size_t old_total = zs.total_out;
            size_t new_cap = cap * 2;
            unsigned char* nb = (unsigned char*)realloc(buf, new_cap);
            if (!nb) { inflateEnd(&zs); free(buf); *out_len = 0; return NULL; }
            buf = nb;
            zs.next_out  = buf + old_total;
            zs.avail_out = (uInt)(new_cap - old_total);
            cap = new_cap;
        }
        *out_len = (int)zs.total_out;
        inflateEnd(&zs);
        return buf;
    }


