    // for binary buffers with embedded NULs (the archive's first NUL
    // is in the pax data, way before any file entry). `__glide_buf_*`
    // ignore strlen entirely.
    static int __glide_buf_byte(const char* s, int i) {
        return (int)((unsigned char)s[i]);
    }
